import { getContext } from '../../server/storage';

export function getDeviceType() {
  return getContext().deviceType;
}

export function getPlatformType() {
  return getContext().platformType;
}

export function getWebviewInfo() {
  return getContext().webviewInfo;
}

export function getDeviceInfo<T = unknown>() {
  return getContext().deviceInfo as T | undefined;
}

export function getSafeAreaInsets<T = unknown>() {
  return getContext().safeAreaInsets as T | undefined;
}

export function getI18n<T = unknown>() {
  return getContext().i18n as T | undefined;
}

export function getNetworkState<T = unknown>() {
  return getContext().networkState as T | undefined;
}

export function getPlatform<T = unknown>() {
  return getContext().platform as T | undefined;
}
